// components/CounterTextarea.tsx
import { useState } from 'react';

export function CounterTextarea({ value, onChange, maxLength = 280, label }: { value: string; onChange: (v: string) => void; maxLength?: number; label: string }) {
  const remaining = maxLength - value.length;
  const over = remaining < 0;
  const warning = remaining < 20 && !over;

  return (
    <label className="block">
      <span className="text-sm font-medium">{label}</span>
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        rows={3}
        className="mt-1 block w-full rounded border p-3 text-base resize-none"
      />
      <div className="flex justify-between items-baseline mt-1 min-h-[1.25rem]">
        <span></span>
        <span
          aria-live="polite"
          className={`
            text-xs tabular-nums
            ${over ? 'text-red-600 font-medium' : warning ? 'text-yellow-600' : 'text-neutral-500'}
          `}
        >{remaining}/{maxLength}</span>
      </div>
    </label>
  );
}

