import { useRef, useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function VideoThumbnail({ thumbnail, videoUrl, title }: { thumbnail: string; videoUrl: string; title: string }) {
  const canHover = useMediaQuery('(hover: hover) and (pointer: fine)', false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [hovered, setHovered] = useState(false);

  return (
    <div
      onMouseEnter={() => { if (canHover) { setHovered(true); videoRef.current?.play().catch(() => {}); } }}
      onMouseLeave={() => { setHovered(false); videoRef.current?.pause(); }}
      onFocus={() => { if (canHover) { setHovered(true); videoRef.current?.play().catch(() => {}); } }}
      onBlur={() => { setHovered(false); videoRef.current?.pause(); }}
      className="relative aspect-video bg-neutral-200 rounded overflow-hidden"
    >
      <img src={thumbnail} alt={title} className={`absolute inset-0 h-full w-full object-cover transition-opacity ${hovered ? 'opacity-0' : 'opacity-100'}`} />
      {canHover && (
        <video
          ref={videoRef}
          src={videoUrl}
          muted
          loop
          playsInline
          preload="metadata"
          className={`absolute inset-0 h-full w-full object-cover transition-opacity ${hovered ? 'opacity-100' : 'opacity-0'}`}
        />
      )}
    </div>
  );
}

