// app/layout.tsx — register SW + offline indicator
'use client';
import { useEffect, useState } from 'react';

export function OfflineIndicator() {
  const [online, setOnline] = useState(true);

  useEffect(() => {
    setOnline(navigator.onLine);
    const onOnline = () => setOnline(true);
    const onOffline = () => setOnline(false);
    window.addEventListener('online', onOnline);
    window.addEventListener('offline', onOffline);
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.register('/sw.js').catch(() => {});
    }
    return () => {
      window.removeEventListener('online', onOnline);
      window.removeEventListener('offline', onOffline);
    };
  }, []);

  if (online) return null;
  return (
    <div role="status" aria-live="polite" className="fixed inset-x-0 top-0 z-50 bg-yellow-500 text-black px-4 py-2 text-sm text-center">
      You're offline. Some features may not work.
    </div>
  );
}

// hooks/useIsSticky.ts
import { useEffect, useRef, useState } from 'react';

export function useIsSticky() {
  const sentinelRef = useRef<HTMLDivElement>(null);
  const [isSticky, setIsSticky] = useState(false);

  useEffect(() => {
    const sentinel = sentinelRef.current;
    if (!sentinel) return;
    const io = new IntersectionObserver(([entry]) => {
      setIsSticky(!entry.isIntersecting);
    }, { threshold: 0 });
    io.observe(sentinel);
    return () => io.disconnect();
  }, []);

  return [sentinelRef, isSticky] as const;
}

