// components/ColumnVisibility.tsx
import { useState, useEffect } from 'react';

export function useColumnVisibility(allColumns: string[]) {
  const [visible, setVisible] = useState<string[]>(allColumns);

  useEffect(() => {
    const stored = localStorage.getItem('table-cols');
    if (stored) setVisible(JSON.parse(stored));
  }, []);

  const toggle = (col: string) => {
    setVisible((v) => {
      const next = v.includes(col) ? v.filter((c) => c !== col) : [...v, col];
      localStorage.setItem('table-cols', JSON.stringify(next));
      return next;
    });
  };

  return { visible, toggle };
}

